import React, { useState } from "react";

function CompareModels() {
  const [results, setResults] = useState(null);
  const [error, setError] = useState("");

  const runCompare = async () => {
    setError("");
    setResults(null);

    try {
      const res = await fetch("http://127.0.0.1:5000/compare", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({})
      });

      const data = await res.json();
      console.log("API:", data); // 🔥 debug

      if (data.status === "success") {
        setResults(data.results);
      } else {
        setError(data.message || "Error from backend");
      }

    } catch (err) {
      setError("Backend connection failed");
    }
  };

  const formatBlock = (title, m) => {
    if (!m) return `${title}\nNo data`;

    return `${title}
TPR: ${m.TPR?.toFixed(2)}%
FNR: ${m.FNR?.toFixed(2)}%
FPR: ${m.FPR?.toFixed(2)}%
TNR: ${m.TNR?.toFixed(2)}%
F1 Score: ${m.F1?.toFixed(2)}%
Confusion → TN: ${m.TN ?? 0} | FP: ${m.FP ?? 0} | FN: ${m.FN ?? 0} | TP: ${m.TP ?? 0}
`;
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Model Comparison</h2>

      <button onClick={runCompare}>Run Comparison</button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {results && (
        <pre style={{ marginTop: "20px", background: "#f4f4f4", padding: "15px" }}>
{formatBlock("OCSVM", results.ocsvm)}

{formatBlock("Isolation Forest", results.isolation_forest)}
        </pre>
      )}
    </div>
  );
}

export default CompareModels;
